// ── BAR HELPER ────────────────────────────────────────────
function bar(id,labels,datasets,opts={}){
  return new Chart(document.getElementById(id),{
    type:'bar',data:{labels,datasets},
    options:{
      responsive:true,maintainAspectRatio:false,indexAxis:opts.horiz?'y':'x',
      plugins:{legend:{display:datasets.length>1,position:'top',labels:{font:{size:11},boxWidth:12}},
        tooltip:{callbacks:{label:ctx=>{const v=ctx.raw;if(opts.pct)return' '+v.toFixed(2)+'%';if(opts.eur)return' €'+v.toLocaleString();return' '+v.toLocaleString()}}}
      },
      scales:{
        x:{grid:{display:opts.horiz?true:false,color:'#F1F5F9'},ticks:{font:{size:11}}},
        y:{grid:{color:'#F1F5F9'},ticks:{font:{size:11},callback:v=>opts.pct?v.toFixed(1)+'%':opts.eur?'€'+v.toLocaleString():v}}
      }
    }
  });
}

