// ── DRAG & DROP CSV UPLOAD ─────────────────────────────────
const dz=document.getElementById('dropzone');
const dzStatus=document.getElementById('dropStatus');
['dragenter','dragover'].forEach(e=>dz.addEventListener(e,ev=>{ev.preventDefault();dz.classList.add('over')}));
['dragleave','drop'].forEach(e=>dz.addEventListener(e,ev=>{ev.preventDefault();dz.classList.remove('over')}));
dz.addEventListener('drop',ev=>{if(ev.dataTransfer.files.length)handleFile(ev.dataTransfer.files[0])});

function handleFile(file){
  if(!file)return;
  dzStatus.className='dropzone-status';dzStatus.style.display='none';
  if(!file.name.endsWith('.csv')){
    dzStatus.textContent='Please upload a .csv file';dzStatus.className='dropzone-status err';dzStatus.style.display='block';return;
  }
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const rows=parseCSV(e.target.result);
      if(rows.length<2)throw new Error('File appears empty');
      const newCamps=processCSVRows(rows);
      // Merge: add only new IDs
      const existingIds=new Set(CAMPAIGNS.map(c=>c.id));
      let added=0;
      newCamps.forEach(c=>{
        if(!existingIds.has(c.id)){CAMPAIGNS.push(c);existingIds.add(c.id);added++}
      });
      if(added===0){
        dzStatus.textContent='✓ File loaded — no new campaigns found (all '+newCamps.length+' already exist)';
        dzStatus.className='dropzone-status ok';dzStatus.style.display='block';
      }else{
        filtered=[...CAMPAIGNS];
        applyFilters();
        dzStatus.textContent='✓ '+added+' new campaigns added! ('+CAMPAIGNS.length+' total)';
        dzStatus.className='dropzone-status ok';dzStatus.style.display='block';
        // Update header count
        document.querySelector('.topbar-left p').textContent=CAMPAIGNS.length+' campaigns · Updated just now · Source: SMS Edge';
      }
    }catch(err){
      dzStatus.textContent='Error: '+err.message;dzStatus.className='dropzone-status err';dzStatus.style.display='block';
    }
  };
  reader.readAsText(file);
}

function parseCSV(text){
  const lines=text.split(/\r?\n/);
  return lines.map(line=>{
    const result=[];let cell='';let inQ=false;
    for(let i=0;i<line.length;i++){
      if(line[i]==='"'){inQ=!inQ}
      else if(line[i]===','&&!inQ){result.push(cell.trim());cell=''}
      else{cell+=line[i]}
    }
    result.push(cell.trim());
    return result;
  }).filter(r=>r.length>1);
}

function processCSVRows(rows){
  const hdr=rows[0].map(h=>h.toLowerCase().trim());
  const idx=(name)=>hdr.indexOf(name);
  const iId=idx('id'),iName=idx('name'),iCountry=idx('country'),iBrand=idx('brand');
  const iList=idx('list name'),iLaps=idx('laps'),iSent=idx('sent');
  const iClicks=idx('clicks'),iLeads=idx('leads'),iSales=idx('sales');
  const iCost=idx('cost'),iCreated=idx('created');

  if(iId<0||iName<0)throw new Error('CSV missing Id or Name columns');

  const ci=v=>{const s=(v||'').replace(/[,\s]/g,'');if(!s||s==='-')return 0;return parseInt(s)||0};
  const cc=v=>{const s=(v||'').replace(/[€$£,\s]/g,'');return parseFloat(s)||0};
  const cs=v=>(v||'').trim();

  return rows.slice(1).filter(r=>cs(r[iName])).map(r=>{
    const name=cs(r[iName]);const list=iList>=0?cs(r[iList]):'';
    const brand=iBrand>=0?cs(r[iBrand]):'';const country=iCountry>=0?cs(r[iCountry]):'';
    const type=(!list&&name.toLowerCase().includes('click'))?'Clicked':'Fresh';
    const sent=iSent>=0?ci(r[iSent]):0;const clicks=iClicks>=0?ci(r[iClicks]):0;
    const sales=iSales>=0?ci(r[iSales]):0;const cost=iCost>=0?cc(r[iCost]):0;
    const leads=iLeads>=0?ci(r[iLeads]):0;const revenue=sales*AVG_SALE;
    const roi=cost>0?(revenue-cost)/cost:0;const ctr=sent>0?clicks/sent:0;
    const cpa=sales>0?cost/sales:0;
    return {
      id:iId>=0?ci(r[iId]):Math.random()*1e9|0,name,country,brand,type,
      list:list||(type==='Clicked'?'Inferred':''),
      laps:iLaps>=0?ci(r[iLaps]):0,sent,clicks,leads,sales,cost,revenue,
      roi:+roi.toFixed(4),ctr:+ctr.toFixed(4),cpa:+cpa.toFixed(2),
      breakeven:+(cost/AVG_SALE).toFixed(1),profitable:revenue>cost,
      created:iCreated>=0?cs(r[iCreated]):''
    };
  });
}

