// ── CONTENT TRACKER ──────────────────────────────────────
// High-click threshold: top 25th percentile of clicks
const allClicks = CAMPAIGNS.map(c=>c.clicks).filter(c=>c>0).sort((a,b)=>b-a);
const highClickThreshold = allClicks[Math.floor(allClicks.length*0.25)]||50;

// In-memory content store: { campaignId: { copy: string, notes: string } }
const contentStore = {};

let contentPage = 1;
const CPS = 15;
let contentSt = {col:'clicks',dir:-1};

function isHighClick(c) {
  return c.clicks >= highClickThreshold;
}

function sortContent(col) {
  if(contentSt.col===col) contentSt.dir*=-1;
  else { contentSt.col=col; contentSt.dir=-1; }
  document.querySelectorAll('#contentTable thead th').forEach(th=>th.className=th.className.replace(/sort-\w+/g,'').trim());
  if(event && event.target) event.target.classList.add(contentSt.dir===1?'sort-asc':'sort-desc');
  contentPage=1;
  renderContentTable();
}

function renderContentTable() {
  const filter = document.getElementById('contentFilter').value;
  let data = [...CAMPAIGNS];

  // Apply filter
  if(filter==='high') data = data.filter(c => isHighClick(c));
  else if(filter==='logged') data = data.filter(c => contentStore[c.id] && (contentStore[c.id].copy || contentStore[c.id].notes));
  else if(filter==='empty') data = data.filter(c => !contentStore[c.id] || (!contentStore[c.id].copy && !contentStore[c.id].notes));

  // Sort
  data.sort((a,b) => {
    let av=a[contentSt.col], bv=b[contentSt.col];
    if(typeof av==='string') av=av.toLowerCase();
    if(typeof bv==='string') bv=bv.toLowerCase();
    return av<bv ? contentSt.dir : av>bv ? -contentSt.dir : 0;
  });

  const total = data.length;
  const pages = Math.ceil(total/CPS);
  const s = (contentPage-1)*CPS;
  const page = data.slice(s, s+CPS);

  // Stats
  document.getElementById('highClickCount').textContent = CAMPAIGNS.filter(c=>isHighClick(c)).length;
  document.getElementById('contentFilledCount').textContent = Object.values(contentStore).filter(v=>v.copy||v.notes).length;

  document.getElementById('contentTbody').innerHTML = page.map(c => {
    const store = contentStore[c.id] || {};
    const copyVal = (store.copy||'').replace(/"/g,'&quot;').replace(/</g,'&lt;');
    const notesVal = (store.notes||'').replace(/"/g,'&quot;').replace(/</g,'&lt;');
    return `<tr>
      <td>${isHighClick(c)?'<span class="high-clicks">🔥</span>':''}</td>
      <td style="max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-weight:500" title="${c.name}">${c.name}</td>
      <td>${c.country}</td>
      <td>${c.brand}</td>
      <td class="num" style="font-weight:600">${c.clicks.toLocaleString()}</td>
      <td class="num">${(c.ctr*100).toFixed(2)}%</td>
      <td class="num">${c.sales}</td>
      <td class="content-cell"><textarea placeholder="Paste SMS copy here…" oninput="saveContent(${c.id},'copy',this.value)">${copyVal}</textarea></td>
      <td class="content-cell"><textarea placeholder="Why did this work? Notes…" oninput="saveContent(${c.id},'notes',this.value)">${notesVal}</textarea></td>
    </tr>`;
  }).join('');

  let btns = `<span>${s+1}–${Math.min(s+CPS,total)} of ${total}</span>`;
  for(let p=1;p<=pages;p++) btns += `<button class="page-btn ${p===contentPage?'active':''}" onclick="goContentPage(${p})">${p}</button>`;
  document.getElementById('contentPagination').innerHTML = btns;
}

function goContentPage(p) { contentPage=p; renderContentTable(); }

function saveContent(id, field, value) {
  if(!contentStore[id]) contentStore[id] = {};
  contentStore[id][field] = value;
  document.getElementById('contentFilledCount').textContent = Object.values(contentStore).filter(v=>v.copy||v.notes).length;
}

function exportContentCSV() {
  const rows = [['Campaign ID','Campaign Name','Country','Brand','Clicks','CTR','Sales','Type','SMS Copy','Notes']];
  CAMPAIGNS.filter(c => contentStore[c.id] && (contentStore[c.id].copy || contentStore[c.id].notes))
    .sort((a,b)=>b.clicks-a.clicks)
    .forEach(c => {
      const s = contentStore[c.id]||{};
      rows.push([c.id, '"'+c.name+'"', c.country, c.brand, c.clicks,
        (c.ctr*100).toFixed(2)+'%', c.sales, c.type,
        '"'+(s.copy||'').replace(/"/g,'""')+'"',
        '"'+(s.notes||'').replace(/"/g,'""')+'"']);
    });
  const csv = rows.map(r=>r.join(',')).join('\n');
  const blob = new Blob([csv], {type:'text/csv'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'sms_content_tracker.csv';
  a.click();
}

